SELECT Sum(Val([Sales Cr_Memo Line.amount])) AS Amount_, [Sales Cr_Memo Header].[Bill-to Customer No_], [Sales Cr_Memo Header].[Bill-to Name], [Sales Cr_Memo Header].[selling season code], [Sales Cr_Memo Line].[Shortcut Dimension 2 Code], [Sales Cr_Memo Header].No_ AS InvoiceNo, [Sales Cr_Memo Header].[posting date] AS DataFattura, [Geographical Zone].Description AS GeoZone1, [Geographical Zone_1].Description AS GeoZone2
FROM ([Sales Cr_Memo Line] INNER JOIN [Sales Cr_Memo Header] ON [Sales Cr_Memo Line].[Document No_] = [Sales Cr_Memo Header].No_) INNER JOIN ((Customer LEFT JOIN [Geographical Zone] ON Customer.[Geographical Zone] = [Geographical Zone].Code) LEFT JOIN [Geographical Zone] AS [Geographical Zone_1] ON Customer.[Geographical Zone 2] = [Geographical Zone_1].Code) ON [Sales Cr_Memo Header].[Bill-to Customer No_] = Customer.No_
WHERE ((([Sales Cr_Memo Line].Type)<>19 And ([Sales Cr_Memo Line].Type)<>20 And ([Sales Cr_Memo Line].Type)<>0))
GROUP BY [Sales Cr_Memo Header].[Bill-to Customer No_], [Sales Cr_Memo Header].[Bill-to Name], [Sales Cr_Memo Header].[selling season code], [Sales Cr_Memo Line].[Shortcut Dimension 2 Code], [Sales Cr_Memo Header].No_, [Sales Cr_Memo Header].[posting date], [Geographical Zone].Description, [Geographical Zone_1].Description
HAVING ((([Sales Cr_Memo Header].[posting date]) Between [Forms]![Principale]![DataIniziale] And [Forms]![Principale]![DataFinale]));

